const express = require('express');
const app = express();
const server = require('http').createServer(app);
const io = require('socket.io')(server);

// Set up Express.js middleware for parsing JSON bodies
app.use(express.json());

// In-memory store for player sessions (replace with a database in production)
let sessions = {};

// Function to generate a new session ID
function generateSessionId() {
  return crypto.randomBytes(16).toString('hex');
}

// Function to authenticate a player and create a new session
function authenticatePlayer(username, password) {
  // Replace this with your own authentication logic (e.g., database query)
  if (username === 'admin' && password === 'password') {
    const sessionId = generateSessionId();
    sessions[sessionId] = { username, score: 0 };
    return sessionId;
  } else {
    return null;
  }
}

// Function to update a player's score
function updateScore(sessionId, newScore) {
  if (sessions[sessionId]) {
    sessions[sessionId].score = newScore;
  }
}

// Handle incoming connections from clients
io.on('connection', (socket) => {
  console.log('Client connected');

  // Listen for authentication requests from clients
  socket.on('authenticate', (data) => {
    const sessionId = authenticatePlayer(data.username, data.password);
    if (sessionId) {
      sessions[sessionId].socketId = socket.id;
      io.to(sessionId).emit('authenticated');
    } else {
      io.to(socket.id).emit('authenticationFailed');
    }
  });

  // Listen for score updates from clients
  socket.on('updateScore', (data) => {
    updateScore(data.sessionId, data.newScore);
    io.emit('scoreUpdate', { sessionId: data.sessionId, newScore: data.newScore });
  });

  // Handle disconnections
  socket.on('disconnect', () => {
    console.log('Client disconnected');
  });
});

